INSERT INTO TB_ADMIN_USER_PWD_HISTORY (
    PWD_HISTORY_ID, ADMIN_USER_ID, PASSWORD, CREATED_AT
) VALUES (
    nextval('SEQ_ADMIN_USER_PWD_HISTORY'), #{adminUserId}, #{password}, #{createdAt}
)

INSERT INTO TB_ADMIN_USER_PWD_HISTORY (
    PWD_HISTORY_ID, ADMIN_USER_ID, PASSWORD, CREATED_AT
) VALUES (
    SEQ_ADMIN_USER_PWD_HISTORY.NEXTVAL, #{adminUserId}, #{password}, #{createdAt}
)

mapper.select:
SELECT PASSWORD
FROM TB_ADMIN_USER_PWD_HISTORY
WHERE ADMIN_USER_ID = #{adminUserId}
ORDER BY CREATED_AT DESC
LIMIT #{limit}

SELECT PASSWORD
FROM TB_ADMIN_USER_PWD_HISTORY
WHERE ADMIN_USER_ID = #{adminUserId}
ORDER BY CREATED_AT DESC
LIMIT 0, #{limit}

